// Normalize text input for robust parsing
const raw = ($input.item.json.raw_text || '').toUpperCase();
const clean = raw.replace(/[^A-Z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
const interactive = $input.item.json.button_id || '';

return {
  ...($input.item.json),
  text: clean,
  action: interactive.toUpperCase()
};

// Session management with 15-minute timeout
const data = this.getWorkflowStaticData('global');
const phone = $input.item.json.from;
const now = Date.now();

// Initialize sessions object
if (!data.sessions) data.sessions = {};

// Create or retrieve session
if (!data.sessions[phone]) {
  data.sessions[phone] = {
    table: null,
    cart: [],
    last_seen: now,
    created_at: now
  };
}

const session = data.sessions[phone];

// Check for session expiry (15 minutes)
const SESSION_TIMEOUT = 900000; // 15 minutes
const expired = (now - session.last_seen) > SESSION_TIMEOUT;

if (expired) {
  session.table = null;
  session.cart = [];
  session.created_at = now;
}

session.last_seen = now;

return {
  ...($input.item.json),
  session: session,
  session_expired: expired
};

