// Parse table number from user input
const text = $input.item.json.text.trim();
const match = text.match(/\b(?:T|TABLE)?\s*(\d+)\b/i);

if (!match) {
  return {
    ...$input.item.json,
    error: 'INVALID_TABLE',
    error_msg: '❌ Invalid table number format.\n\nPlease send just the number (e.g., "5" or "table 12")'
  };
}

const tableNum = parseInt(match[1]);
const MAX_TABLES = 200;

if (tableNum < 1 || tableNum > MAX_TABLES) {
  return {
    ...$input.item.json,
    error: 'TABLE_OUT_RANGE',
    error_msg: `❌ Table number must be between 1 and ${MAX_TABLES}`
  };
}

// Save table to session
const data = this.getWorkflowStaticData('global');
data.sessions[$input.item.json.from].table = tableNum.toString();

return {
  ...$input.item.json,
  session: data.sessions[$input.item.json.from]
};

