// Format cart for display
const session = $input.item.json.session;

if (!session.cart || session.cart.length === 0) {
  return {
    ...$input.item.json,
    cart_empty: true,
    cart_text: '🛒 *Your cart is empty*\n\nTap "View Menu" to start ordering!'
  };
}

// Format cart items
const lines = session.cart.map(item => 
  `${item.qty}x ${item.name}\n   ₹${item.price.toFixed(2)} × ${item.qty} = ₹${(item.price * item.qty).toFixed(2)}`
);

const total = session.cart.reduce((sum, item) => sum + (item.price * item.qty), 0);
const itemCount = session.cart.reduce((sum, item) => sum + item.qty, 0);

const cartText = `🛒 *Your Cart (Table ${session.table})*\n\n${lines.join('\n\n')}\n\n${'━'.repeat(30)}\n*Total Items:* ${itemCount}\n*Total Amount:* ₹${total.toFixed(2)}`;

return {
  ...$input.item.json,
  cart_empty: false,
  cart_text: cartText,
  cart_total: total,
  cart_item_count: itemCount
};

