// Parse item codes and quantities from user input
const tokens = $input.item.json.text.split(/\s+/);
const items = [];

for (let i = 0; i < tokens.length; i++) {
  // Match item code pattern (e.g., B1, F12, D3)
  if (/^[A-Z]+\d+$/.test(tokens[i])) {
    let qty = 1;

    // Check if next token is a quantity
    if (i + 1 < tokens.length && /^\d+$/.test(tokens[i + 1])) {
      qty = parseInt(tokens[i + 1]);
      i++; // Skip the quantity token
    }

    // Validate quantity
    if (qty < 1 || qty > 20) {
      return {
        ...$input.item.json,
        error: 'INVALID_QTY',
        error_msg: '❌ Quantity must be between 1 and 20 per item.\n\nPlease try again.'
      };
    }

    items.push({ code: tokens[i], qty });
  }
}

if (items.length === 0) {
  return {
    ...$input.item.json,
    error: 'NO_ITEMS',
    error_msg: '❌ No valid item codes found.\n\n*Format:* B1 2 F3 1\n(This orders 2x B1 and 1x F3)\n\nTap "View Menu" to see all codes.'
  };
}

return {
  ...$input.item.json,
  parsed_items: items
};

// Validate items against menu and add to cart
const menuItems = $input.all().slice(1).map(i => i.json);
const currentData = $input.item.json;
const parsedItems = currentData.parsed_items;
const data = this.getWorkflowStaticData('global');
const session = data.sessions[currentData.from];

const validItems = [];
const invalidItems = [];

// Validate each item against menu
for (const item of parsedItems) {
  const menuItem = menuItems.find(m => m.Code === item.code);

  if (menuItem && menuItem.Available !== 'No') {
    validItems.push({
      code: item.code,
      name: menuItem.Name,
      price: parseFloat(menuItem.Price),
      qty: item.qty,
      category: menuItem.Category || 'Other'
    });
  } else if (menuItem && menuItem.Available === 'No') {
    invalidItems.push(`${item.code} (unavailable)`);
  } else {
    invalidItems.push(item.code);
  }
}

// Check for invalid items
if (invalidItems.length > 0) {
  return {
    ...currentData,
    error: 'INVALID_CODES',
    error_msg: `❌ *Invalid or unavailable items:*\n${invalidItems.join(', ')}\n\nPlease check the menu and try again.`
  };
}

// Add valid items to cart
for (const item of validItems) {
  const existing = session.cart.find(c => c.code === item.code);

  if (existing) {
    existing.qty += item.qty;
  } else {
    session.cart.push(item);
  }
}

return {
  ...currentData,
  session: session,
  added_items: validItems
};
